import React from 'react';

const ContactoPage = () => {
  const items = [
    {
      src: '/media/contactoPage/LP.png',
      alt: 'Universidad Católica Boliviana La Paz',
      text: 'Universidad Católica Boliviana\nLA PAZ',
    },
    {
      src: '/media/contactoPage/SIS - H.png',
      alt: 'Carrera de Ingeniería de Sistemas',
      text: 'Carrera de Ingeniería\nde Sistemas',
    },
    {
      src: '/media/contactoPage/II.png',
      alt: 'Carrera de Ingeniería Innovación Empresarial',
      text: 'Carrera de Ingeniería\nInnovación empresarial',
    },
  ];

  return (
    <main style={styles.page}>
      <h1 style={styles.title}>UNIVERSIDAD CATÓLICA BOLIVIANA</h1>
      <section style={styles.grid}>
        {items.map(({ src, alt, text }, idx) => (
          <article key={idx} style={styles.card} tabIndex={0}>
            <div style={styles.imageWrapper}>
              <img src={src} alt={alt} style={styles.image} />
            </div>
            <p style={styles.text}>
              {text.split('\n').map((line, i) => (
                <React.Fragment key={i}>
                  {line}
                  <br />
                </React.Fragment>
              ))}
            </p>
          </article>
        ))}
      </section>
    </main>
  );
};

const styles = {
  page: {
    backgroundColor: '#F5EEE2',
    minHeight: '100vh',
    padding: '4rem 2rem',
    fontFamily: "'Montserrat', sans-serif",
    color: '#032F27',
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
  },
  title: {
    fontSize: '3rem',
    fontWeight: '900',
    marginBottom: '3.5rem',
    letterSpacing: '0.15em',
    textAlign: 'center',
    color: '#032F27',
  },
  grid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(3, 320px)',
    gap: '2rem',
    justifyContent: 'center',
    width: '100%',
    maxWidth: 1024,
  },
  card: {
    backgroundColor: '#FDF8F0',
    borderRadius: '24px',
    boxShadow: '0 10px 20px rgba(3,47,39,0.1)',
    padding: '2rem',
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    cursor: 'default',
    userSelect: 'none',
    height: 320, // un poco más para que quepa la imagen y el texto sin problemas
    color: '#032F27',
    textAlign: 'center',
    transition: 'transform 0.3s ease, box-shadow 0.3s ease',
  },
  imageWrapper: {
    width: 160,   // tamaño fijo para contener imagenes diferentes
    height: 160,  // mismo tamaño para todas las imágenes
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    marginBottom: '1.5rem',
    borderRadius: 16,
    overflow: 'hidden',
    boxShadow: '0 6px 15px rgba(3,47,39,0.1)',
    backgroundColor: '#ffffff', // fondo blanco para que las imágenes pequeñas se vean bien
  },
  image: {
    maxWidth: '100%',
    maxHeight: '100%',
    objectFit: 'contain', // para no recortar imágenes y ajustarlas dentro del contenedor
  },
  text: {
    fontSize: '1.15rem',
    fontWeight: '600',
    lineHeight: 1.5,
    whiteSpace: 'pre-line',
    color: '#032F27',
  },
};

export default ContactoPage;
